import Foundation

func solve(landStartTime: Array<Int64>, landDuration: Array<Int64>, waterStartTime: Array<Int64>, waterDuration: Array<Int64>) -> Int64 {
    var minTime = Int64.max

    // Try all combinations of one land and one water attraction
    for i in 0..<landStartTime.count {
        for j in 0..<waterStartTime.count {
            // Land first, then water
            let landEnd = max(landStartTime[i], Int64(0)) + landDuration[i]
            let waterStart = max(landEnd, waterStartTime[j])
            let waterEnd = waterStart + waterDuration[j]
            minTime = min(minTime, waterEnd)

            // Water first, then land
            let waterEndFirst = max(waterStartTime[j], Int64(0)) + waterDuration[j]
            let landStart = max(waterEndFirst, landStartTime[i])
            let landEndSecond = landStart + landDuration[i]
            minTime = min(minTime, landEndSecond)
        }
    }

    return minTime
}
